<script setup lang="ts">
import { computed, onMounted, ref, watch } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import MesLayout from '@/layouts/MesLayout.vue'
import { get, post } from '@/api/client'
type Version = { id:number; versionNo:string; revisionType?:string; status:string; remark?:string; createdAt?:string; effectiveFrom?:string; modelVersionId?:number }
const route=useRoute(), router=useRouter(), sopId=computed(()=>Number(route.query.sopId || 0)); const rows=ref<Version[]>([]),error=ref(''),loading=ref(false),creating=ref(false); const versionNo=ref(''), remark=ref('')
const title=computed(()=>String(route.query.name || 'SOP 版本管理'))
const date=(v?:string)=>v?v.replace('T',' ').slice(0,16):'-'
async function load(){ if(!sopId.value){rows.value=[];error.value='请从 SOP 文档页面选择文档后查看版本';return};loading.value=true;error.value='';try{rows.value=await get<Version[]>(`/production/sop/documents/${sopId.value}/versions`)}catch(e){error.value=e instanceof Error?e.message:'版本加载失败'}finally{loading.value=false}}
async function create(){try{await post(`/production/sop/documents/${sopId.value}/versions`,{versionNo:versionNo.value||null,revisionType:'NEW',remark:remark.value||null});creating.value=false;versionNo.value='';remark.value='';await load()}catch(e){error.value=e instanceof Error?e.message:'新建版本失败'}}
async function action(row:Version, name:'submit'|'reject'|'approve'|'publish'|'disable'|'void'){const remark=window.prompt('操作备注（可留空）','') ?? null;if(remark===null)return;try{await post(`/production/sop/versions/${row.id}/${name}`,{remark});await load()}catch(e){error.value=e instanceof Error?e.message:'版本操作失败'}}
async function copy(row:Version){try{await post(`/production/sop/versions/${row.id}/copy`,{revisionType:'MINOR'});await load()}catch(e){error.value=e instanceof Error?e.message:'复制版本失败'}}
function steps(row:Version){router.push({path:'/sop/steps',query:{versionId:row.id,name:`${title.value} · ${row.versionNo}`,modelVersionId:row.modelVersionId}})}
function bindings(row:Version){router.push({path:'/sop/bindings',query:{versionId:row.id,name:`${title.value} · ${row.versionNo}`}})}
onMounted(load);watch(sopId,load)
</script>
<template><MesLayout active="sop-versions"><header class="app-header"><div class="header-breadcrumb"><span>电子 SOP</span><span class="bc-sep">/</span><RouterLink to="/sop/documents">SOP 文档</RouterLink><span class="bc-sep">/</span><span class="bc-current">版本管理</span></div><div class="header-actions"><button class="btn btn-primary btn-sm" :disabled="!sopId" @click="creating=true">+ 新建版本</button><span class="user-avatar">张</span></div></header><main class="app-main"><h1 class="page-title">{{ title }}</h1><div v-if="error" class="alert alert-error mb-5"><span class="alert-icon">!</span>{{error}}</div><div class="data-table-wrap"><table class="data-table"><thead><tr><th>版本号</th><th>变更类型</th><th>变更说明</th><th>生效时间</th><th>创建时间</th><th>状态</th><th>操作</th></tr></thead><tbody><tr v-if="loading"><td colspan="7">正在加载...</td></tr><tr v-else-if="!rows.length"><td colspan="7">暂无版本</td></tr><tr v-for="row in rows" :key="row.id"><td class="cell-mono">{{row.versionNo}}</td><td>{{row.revisionType||'-'}}</td><td>{{row.remark||'-'}}</td><td>{{date(row.effectiveFrom)}}</td><td>{{date(row.createdAt)}}</td><td><span class="badge badge-status-ok"><span class="badge-dot"></span>{{row.status}}</span></td><td class="cell-actions"><button class="btn btn-ghost btn-sm" @click="steps(row)">步骤/附件</button><button class="btn btn-ghost btn-sm" @click="bindings(row)">绑定</button><button class="btn btn-ghost btn-sm" @click="copy(row)">复制</button><button v-if="row.status==='DRAFT'||row.status==='REJECTED'" class="btn btn-ghost btn-sm" @click="action(row,'submit')">提交</button><template v-if="row.status==='PENDING_REVIEW'"><button class="btn btn-ghost btn-sm" @click="action(row,'reject')">驳回</button><button class="btn btn-ghost btn-sm" @click="action(row,'approve')">批准</button></template><button v-if="row.status==='APPROVED'" class="btn btn-primary btn-sm" @click="action(row,'publish')">发布</button><button v-if="row.status==='EFFECTIVE'||row.status==='PENDING_EFFECTIVE'" class="btn btn-ghost btn-sm" @click="action(row,'disable')">停用</button><button v-if="row.status==='EFFECTIVE'||row.status==='PENDING_EFFECTIVE'||row.status==='DISABLED'||row.status==='REJECTED'" class="btn btn-ghost btn-sm" @click="action(row,'void')">作废</button></td></tr></tbody></table><div class="pagination">共 {{rows.length}} 个版本</div></div><div v-if="creating" class="sop-mask" @click.self="creating=false"><form class="sop-dialog" @submit.prevent="create"><div class="card-header"><h2 class="card-title">新建版本</h2></div><label>版本号（留空自动生成）<input v-model="versionNo" class="form-input" placeholder="如 V2.0"></label><label>变更说明<textarea v-model="remark" class="form-input" rows="3"></textarea></label><div class="dialog-actions"><button type="button" class="btn btn-secondary" @click="creating=false">取消</button><button class="btn btn-primary">保存</button></div></form></div></main><footer class="app-statusbar"><span class="statusbar-item"><span class="dot ok"></span>版本管理</span><span class="statusbar-sep">|</span><span class="statusbar-item">{{rows.length}} 个版本</span></footer></MesLayout></template>
<style scoped>.sop-mask{position:fixed;inset:0;z-index:20;background:rgba(15,23,42,.38);display:grid;place-items:center}.sop-dialog{width:min(480px,calc(100vw - 32px));background:#fff;border-radius:8px;padding:20px;box-shadow:0 18px 50px rgba(15,23,42,.28);display:grid;gap:14px}.sop-dialog label{display:grid;gap:7px;font-size:13px}.dialog-actions{display:flex;justify-content:flex-end;gap:10px;margin-top:8px}</style>
